  <line x1="20" y1="350" x2="650" y2="350" stroke="#71717a"/>
  <text x="20" y="368" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">0%</text>
  <text x="146" y="368" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">20%</text>
  <text x="272" y="368" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">40%</text>
